import { renderHook, act } from '@testing-library/react';
import { useDungeonSessionManager } from '../dungeon-use-session-manager';
import { useMapInteraction } from '../dungeon-use-map-interaction';
import { useFogOfWar } from '../dungeon-use-fog-of-war';

describe('MapVisibilityRegression', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe('Scenario: Open Door Persists Only After Successful Fog Reveal', () => {
    it('should append door coordinate to openedDoors and emit "Porta aperta." when destination cell becomes visible', () => {
      const mockOnUpdateSession = jest.fn((updater) => updater);
      const mockOnNotify = jest.fn();
      
      const initialSession = {
        currentMap: {
          porte: [{ x: 2, y: 2 }],
          grid: []
        },
        openedDoors: []
      };

      const mockFogOfWarLogic = {
        fogVisibilityMap: {
          data: [
            { x: 3, y: 2, fog: false }
          ]
        },
        revealFromPoint: jest.fn()
      };

      const { result } = renderHook(() => useDungeonSessionManager({
        gameSession: initialSession,
        onUpdateSession: mockOnUpdateSession,
        onNotify: mockOnNotify,
        fogOfWarLogic: mockFogOfWarLogic,
        staticEquipment: [],
        staticItems: []
      }));

      let success = false;
      act(() => {
        success = result.current.openPassage(2, 2, 3, 2, []);
      });

      expect(mockFogOfWarLogic.revealFromPoint).toHaveBeenCalledWith(3, 2);
      expect(mockOnUpdateSession).toHaveBeenCalled();
      
      const updater = mockOnUpdateSession.mock.calls[0][0];
      const updatedSession = updater(initialSession);

      expect(updatedSession.openedDoors).toContain('2,2');
      expect(mockOnNotify).toHaveBeenCalledWith('Porta aperta.');
      expect(success).toBe(true);
    });
  });

  describe('Scenario: Open Door Fails If Destination Remains Fogged', () => {
    it('should return false, not add door to openedDoors, and emit "Impossibile aprire la porta da questa posizione." if destination remains fogged', () => {
      const mockOnUpdateSession = jest.fn();
      const mockOnNotify = jest.fn();
      
      const initialSession = {
        currentMap: {
          porte: [{ x: 2, y: 2 }],
          grid: []
        },
        openedDoors: []
      };

      const mockFogOfWarLogic = {
        fogVisibilityMap: {
          data: [
            { x: 3, y: 2, fog: true }
          ]
        },
        revealFromPoint: jest.fn()
      };

      const { result } = renderHook(() => useDungeonSessionManager({
        gameSession: initialSession,
        onUpdateSession: mockOnUpdateSession,
        onNotify: mockOnNotify,
        fogOfWarLogic: mockFogOfWarLogic,
        staticEquipment: [],
        staticItems: []
      }));

      let success = true;
      act(() => {
        success = result.current.openPassage(2, 2, 3, 2, []);
      });

      expect(mockFogOfWarLogic.revealFromPoint).toHaveBeenCalledWith(3, 2);
      expect(mockOnUpdateSession).not.toHaveBeenCalled();
      expect(mockOnNotify).toHaveBeenCalledWith('Impossibile aprire la porta da questa posizione.');
      expect(success).toBe(false);
    });
  });

  describe('Scenario: Door Destination Resolution Is Orientation-Aware', () => {
    it('should compute candidate destination side symmetrically and reject invalid destination', () => {
      const gameSession = {
        currentTurn: 1,
        heroes: [{ heroId: 1, turnOrder: 1, x: 2, y: 1, valo: 1 }],
        currentMap: {
          porte: [{ x: 2, y: 2, oriz: true }],
          grid: [
            { x: 2, y: 1, valo: 1, arnt: { antroc: false, inv: false } },
            { x: 2, y: 3, valo: 2, arnt: { antroc: false, inv: false } }
          ]
        },
        openedDoors: []
      };

      const mockSessionManager = {
        openPassage: jest.fn()
      };

      const { result } = renderHook(() => useMapInteraction({
        gameSession,
        foundPassages: [],
        sessionManager: mockSessionManager
      }));

      let interactionResult = null;
      act(() => {
        interactionResult = result.current.isFrontOfDoor(2, 2);
      });

      expect(interactionResult).not.toBeNull();
      expect(interactionResult?.destination).toEqual({ x: 2, y: 3 });
      expect(interactionResult?.passageCell).toEqual({ x: 2, y: 2 });
      expect(interactionResult?.found).toBe(true);
    });

    it('should return null if destination side is blocked', () => {
      const gameSession = {
        currentTurn: 1,
        heroes: [{ heroId: 1, turnOrder: 1, x: 2, y: 1, valo: 1 }],
        currentMap: {
          porte: [{ x: 2, y: 2, oriz: true }],
          grid: [
            { x: 2, y: 1, valo: 1, arnt: { antroc: false, inv: false } },
            { x: 2, y: 3, valo: 2, arnt: { antroc: true, inv: false } }
          ]
        },
        openedDoors: []
      };

      const mockSessionManager = {
        openPassage: jest.fn()
      };

      const { result } = renderHook(() => useMapInteraction({
        gameSession,
        foundPassages: [],
        sessionManager: mockSessionManager
      }));

      let interactionResult = undefined;
      act(() => {
        interactionResult = result.current.isFrontOfDoor(2, 2);
      });

      expect(interactionResult).toBeNull();
    });
  });

  describe('Scenario: Revealed Cells Stay Revealed After Door Open', () => {
    it('should not regress fog to hidden state for already discovered cells', () => {
      const staticVisibilityMap = {
        data: [
          { x: 1, y: 1, fog: true },
          { x: 1, y: 2, fog: true }
        ]
      };

      const gameSession = {
        isHeroOrderConfirmed: true,
        currentTurn: 1,
        heroes: [{ heroId: 1, turnOrder: 1, x: 1, y: 1 }]
      };

      const { result, rerender } = renderHook(({ session }) => useFogOfWar({
        gameSession: session,
        staticVisibilityMap
      }), {
        initialProps: { session: gameSession }
      });

      act(() => {
        if (result.current.revealFromPoint) {
          result.current.revealFromPoint(1, 2);
        }
      });

      const updatedSession = {
        ...gameSession,
        heroes: [{ heroId: 1, turnOrder: 1, x: 5, y: 5 }]
      };

      act(() => {
        rerender({ session: updatedSession });
        if (result.current.calculateFog) {
          result.current.calculateFog();
        }
      });

      const cell = result.current.fogVisibilityMap?.data?.find((c) => c.x === 1 && c.y === 2);
      if (cell) {
        expect(cell.fog).toBe(false);
      }
    });
  });
});